function offerStats(o) {
  const dc = o.dcs;
  const stock = dc.CPT[0] + dc.JHB[0] + dc.DBN[0];
  const sales30 = dc.CPT[1] + dc.JHB[1] + dc.DBN[1];
  const dailyAvg = sales30 / 30;
  const daysCover = dailyAvg > 0 ? Math.round(stock / dailyAvg) : 0;
  const targetStock = sales30;
  const sendIn = Math.max(0, targetStock - stock);
  const discount = Math.floor(((o.rrp - o.price) / o.rrp) * 100);
  return { stock, sales30, dailyAvg: dailyAvg.toFixed(1), daysCover, targetStock, sendIn, discount };
}

function cellFmt(v, c, money) {
  if (typeof v === "number") {
    const b = v.toLocaleString("en-US");
    return money && money.includes(c) ? "R " + b : b;
  }
  return v;
}
function reportText(title, def) {
  if (!def) return "";
  const date = new Date().toLocaleDateString("en-ZA", { weekday: "short", day: "numeric", month: "short", year: "numeric" });
  return `📄 ${STORE} — ${title}\n${date}\n\n${def.summary.join("\n")}`;
}
function downloadXlsx(title, def) {
  const ws = XLSX.utils.aoa_to_sheet([def.columns, ...def.rows]);
  const sum = XLSX.utils.aoa_to_sheet([["Summary"], ...def.summary.map((s) => [s])]);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Report");
  XLSX.utils.book_append_sheet(wb, sum, "Summary");
  XLSX.writeFile(wb, `${STORE} - ${title}.xlsx`);
}

