const rand = (v) => "R\u00A0" + v.toLocaleString("en-US");

function relTime(ts, now) {
  const s = Math.max(0, Math.floor((now - ts) / 1000));
  if (s < 10) return "just now";
  if (s < 60) return s + "s ago";
  const m = Math.floor(s / 60);
  if (m < 60) return m + "m ago";
  return Math.floor(m / 60) + "h ago";
}

// Next-run schedule helpers (all take current time in ms)
function nextDaily(h, m, now) {
  const d = new Date(now); d.setHours(h, m, 0, 0);
  if (d.getTime() <= now) d.setDate(d.getDate() + 1);
  return d.getTime();
}
function nextHourly(now) {
  const d = new Date(now); d.setMinutes(0, 0, 0); d.setHours(d.getHours() + 1);
  return d.getTime();
}
function nextWeekly(wd, h, m, now) {
  const d = new Date(now); d.setHours(h, m, 0, 0);
  let diff = (wd - d.getDay() + 7) % 7;
  if (diff === 0 && d.getTime() <= now) diff = 7;
  d.setDate(d.getDate() + diff);
  return d.getTime();
}
function nextMonthly(day, h, m, now) {
  const d = new Date(now); d.setDate(day); d.setHours(h, m, 0, 0);
  if (d.getTime() <= now) { d.setMonth(d.getMonth() + 1); d.setDate(day); d.setHours(h, m, 0, 0); }
  return d.getTime();
}
function fmtUntil(ms) {
  if (ms <= 0) return "now";
  const s = Math.floor(ms / 1000);
  const m = Math.floor(s / 60) % 60;
  const h = Math.floor(s / 3600) % 24;
  const dd = Math.floor(s / 86400);
  if (dd > 0) return `${dd}d ${h}h`;
  if (h > 0) return `${h}h ${m}m`;
  if (m > 0) return `${m}m`;
  return `${s}s`;
}

