      setBuyBox((list) => list.map((x) => x.name === b.name ? { ...x, yourPrice: cur, min: repriceMin, preferred: repriceMax, status: cur <= x.boxPrice ? (x.sellers === 0 ? "sole" : "winning") : "losing" } : x));
