                                <button onClick={saveName} style={{ flex: 1, padding: "11px 0", borderRadius: 11, border: "none", background: WA, color: "#fff", fontSize: 13.5, fontWeight: 700, cursor: "pointer", fontFamily: FONT }}>Save</button>
